import type { KeyboardEvent, PointerEvent, ReactNode } from "react";

export type EntryNodeStatusTone =
  | "accessible"
  | "available"
  | "binding"
  | "bound"
  | "complete"
  | "creating"
  | "degraded"
  | "deleting"
  | "error"
  | "failed"
  | "inaccessible"
  | "pending"
  | "progressing"
  | "ready"
  | "running"
  | "shutdown"
  | "stopped"
  | "stopping"
  | "succeeded"
  | "unhealthy"
  | "unknown";

export interface EntryNodeStatus {
  label: string;
  tone?: EntryNodeStatusTone;
}

export interface EntryNodeStates {
  name: string;
  status?: EntryNodeStatus;
}

export type EntryNodeDomainKey = "access" | "private" | "public";

export interface EntryNodeDomain {
  label: string;
  status?: EntryNodeStatus;
  value: string;
}

export type EntryNodeDomains = Partial<
  Record<EntryNodeDomainKey, EntryNodeDomain>
>;

/** Screen-space drag angle in degrees: 0 = right, 90 = down. */
export type EntryNodeDragAngle = number;

export type EntryNodeConnectionSide = "bottom" | "left" | "right" | "top";

export type EntryNodeConnectionEvent =
  | KeyboardEvent<HTMLButtonElement>
  | PointerEvent<HTMLButtonElement>;

export interface EntryNodeInteractionState {
  dragAngle?: EntryNodeDragAngle;
  dragging?: boolean;
}

export interface EntryNodeState {
  copiedDomainKey?: EntryNodeDomainKey | null;
  domains?: EntryNodeDomains;
  interaction?: EntryNodeInteractionState;
  states: EntryNodeStates;
}

export interface EntryNodeActions {
  collapse?: () => void;
  copyDomain?: (key: EntryNodeDomainKey, value: string) => Promise<void> | void;
  expand?: () => void;
  startConnection?: (
    side: EntryNodeConnectionSide,
    event: EntryNodeConnectionEvent
  ) => void;
}

export interface EntryNodeMeta {
  copiedFeedbackMs?: number;
  expanded?: boolean;
}

export interface EntryNodeContextValue {
  actions: Required<Pick<EntryNodeActions, "copyDomain">> &
    Omit<EntryNodeActions, "copyDomain">;
  meta: EntryNodeMeta;
  state: EntryNodeState;
}

export interface EntryNodeProviderProps {
  children?: ReactNode;
  value: EntryNodeContextValue;
}

export interface EntryNodeRootProps {
  actions?: EntryNodeActions;
  children?: ReactNode;
  defaultExpanded?: boolean;
  expanded?: boolean;
  meta?: Omit<EntryNodeMeta, "expanded">;
  onExpandedChange?: (expanded: boolean) => void;
  state: EntryNodeState;
}

import type {
  EntryNodeConnectionSide,
  EntryNodeDomainKey,
  EntryNodeStatusTone,
} from "./entry-node.types";

const DOMAIN_KEYS = new Set<EntryNodeDomainKey>([
  "access",
  "private",
  "public",
]);

const CONNECTION_SIDES = new Set<EntryNodeConnectionSide>([
  "bottom",
  "left",
  "right",
  "top",
]);

export function isEntryNodeDomainKey(
  input: string
): input is EntryNodeDomainKey {
  return DOMAIN_KEYS.has(input as EntryNodeDomainKey);
}

export function isEntryNodeConnectionSide(
  input: string
): input is EntryNodeConnectionSide {
  return CONNECTION_SIDES.has(input as EntryNodeConnectionSide);
}

export function normalizeEntryNodeStatus(
  input: string | undefined
): EntryNodeStatusTone {
  const normalized = input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");

  switch (normalized) {
    case "accessible":
    case "available":
    case "bound":
    case "complete":
    case "ready":
    case "running":
    case "succeeded":
      return normalized;
    case "binding":
    case "creating":
    case "pending":
    case "progressing":
      return normalized;
    case "deleting":
    case "stopping":
      return normalized;
    case "shutdown":
    case "stopped":
      return normalized;
    case "degraded":
    case "error":
    case "failed":
    case "inaccessible":
    case "unhealthy":
      return normalized;
    default:
      return "unknown";
  }
}

"use client";

import { createContext, use } from "react";

import type { EntryNodeContextValue } from "./entry-node.types";

export const EntryNodeContext = createContext<EntryNodeContextValue | null>(
  null
);

export function useEntryNode(): EntryNodeContextValue {
  const value = use(EntryNodeContext);
  if (!value) {
    throw new Error(
      "EntryNode: compound components must be used within EntryNode.Root or EntryNode.Provider"
    );
  }
  return value;
}

"use client";

import { EntryNodeContext } from "./entry-node.context";
import type { EntryNodeProviderProps } from "./entry-node.types";

export function EntryNodeProvider({ children, value }: EntryNodeProviderProps) {
  return <EntryNodeContext value={value}>{children}</EntryNodeContext>;
}

"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { EntryNodeDefaultView } from "./entry-node.default-view";
import { EntryNodeProvider } from "./entry-node.provider";
import type {
  EntryNodeConnectionEvent,
  EntryNodeConnectionSide,
  EntryNodeContextValue,
  EntryNodeDomainKey,
  EntryNodeRootProps,
} from "./entry-node.types";

const DEFAULT_COPIED_FEEDBACK_MS = 1200;

async function copyTextToClipboard(value: string) {
  if (typeof navigator === "undefined" || !navigator.clipboard) {
    return;
  }

  await navigator.clipboard.writeText(value);
}

export function EntryNodeRoot({
  actions,
  children,
  defaultExpanded = false,
  expanded,
  meta,
  onExpandedChange,
  state,
}: EntryNodeRootProps) {
  const [internalExpanded, setInternalExpanded] = useState(defaultExpanded);
  const [internalCopiedDomainKey, setInternalCopiedDomainKey] =
    useState<EntryNodeDomainKey | null>(null);
  const resetTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const expandedControlled = expanded !== undefined;
  const copiedDomainControlled = state.copiedDomainKey !== undefined;
  const resolvedExpanded = expanded ?? internalExpanded;

  useEffect(
    () => () => {
      if (resetTimerRef.current) {
        clearTimeout(resetTimerRef.current);
      }
    },
    []
  );

  const setExpandedState = useCallback(
    (nextExpanded: boolean) => {
      if (!expandedControlled) {
        setInternalExpanded(nextExpanded);
      }
      onExpandedChange?.(nextExpanded);
    },
    [expandedControlled, onExpandedChange]
  );

  const collapse = useCallback(() => {
    actions?.collapse?.();
    setExpandedState(false);
  }, [actions?.collapse, setExpandedState]);

  const expand = useCallback(() => {
    actions?.expand?.();
    setExpandedState(true);
  }, [actions?.expand, setExpandedState]);

  const copyDomain = useCallback(
    async (key: EntryNodeDomainKey, domainValue: string) => {
      if (!domainValue) {
        return;
      }

      if (actions?.copyDomain) {
        await actions.copyDomain(key, domainValue);
      } else {
        await copyTextToClipboard(domainValue);
      }

      if (!copiedDomainControlled) {
        setInternalCopiedDomainKey(key);

        if (resetTimerRef.current) {
          clearTimeout(resetTimerRef.current);
        }

        resetTimerRef.current = setTimeout(() => {
          setInternalCopiedDomainKey(null);
          resetTimerRef.current = null;
        }, meta?.copiedFeedbackMs ?? DEFAULT_COPIED_FEEDBACK_MS);
      }
    },
    [actions?.copyDomain, copiedDomainControlled, meta?.copiedFeedbackMs]
  );

  const startConnection = useCallback(
    (side: EntryNodeConnectionSide, event: EntryNodeConnectionEvent) => {
      actions?.startConnection?.(side, event);
    },
    [actions?.startConnection]
  );

  const value = useMemo(
    (): EntryNodeContextValue => ({
      actions: {
        collapse,
        copyDomain,
        expand,
        startConnection,
      },
      meta: {
        ...meta,
        expanded: resolvedExpanded,
      },
      state: {
        ...state,
        copiedDomainKey: copiedDomainControlled
          ? state.copiedDomainKey
          : internalCopiedDomainKey,
      },
    }),
    [
      collapse,
      copiedDomainControlled,
      copyDomain,
      expand,
      internalCopiedDomainKey,
      meta,
      resolvedExpanded,
      startConnection,
      state,
    ]
  );

  return (
    <EntryNodeProvider value={value}>
      {children ?? <EntryNodeDefaultView />}
    </EntryNodeProvider>
  );
}

