"use client";

import { cn } from "@workspace/ui/lib/utils";

import { normalizeEntryNodeStatus } from "./entry-node.guards";
import type { EntryNodeStatus, EntryNodeStatusTone } from "./entry-node.types";

interface StatusVisual {
  breathing: boolean;
  dotClassName: string;
  pillClassName: string;
}

const GREEN: StatusVisual = {
  breathing: true,
  dotClassName: "bg-green-500",
  pillClassName: "bg-green-500/30 text-zinc-50",
};
const BLUE: StatusVisual = {
  breathing: true,
  dotClassName: "bg-blue-500",
  pillClassName: "bg-blue-500/30 text-zinc-50",
};
const YELLOW: StatusVisual = {
  breathing: true,
  dotClassName: "bg-yellow-500",
  pillClassName: "bg-yellow-500/30 text-zinc-50",
};
const GRAY_BREATHING: StatusVisual = {
  breathing: true,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
};
const GRAY_STATIC: StatusVisual = {
  breathing: false,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
};
const RED: StatusVisual = {
  breathing: true,
  dotClassName: "bg-red-500",
  pillClassName: "bg-red-500/30 text-zinc-50",
};

function getStatusVisual(tone: EntryNodeStatusTone): StatusVisual {
  switch (tone) {
    case "accessible":
    case "available":
    case "bound":
    case "complete":
    case "ready":
    case "running":
    case "succeeded":
      return GREEN;
    case "binding":
    case "creating":
    case "pending":
    case "progressing":
      return BLUE;
    case "deleting":
      return YELLOW;
    case "stopping":
      return GRAY_BREATHING;
    case "degraded":
    case "error":
    case "failed":
    case "inaccessible":
    case "unhealthy":
      return RED;
    case "shutdown":
    case "stopped":
    case "unknown":
      return GRAY_STATIC;
    default:
      return GRAY_STATIC;
  }
}

function resolveTone(status: EntryNodeStatus | undefined) {
  return status?.tone ?? normalizeEntryNodeStatus(status?.label);
}

export function EntryNodeStatusDot({
  className,
  size = "default",
  status,
}: {
  className?: string;
  size?: "collapsed" | "default" | "small";
  status?: EntryNodeStatus;
}) {
  const visual = getStatusVisual(resolveTone(status));
  const dotSize = size === "default" ? "size-3" : "size-2";
  const pingSize = size === "default" ? "size-2.5" : "size-2";

  return (
    <span
      aria-hidden
      className={cn(
        "relative flex shrink-0 items-center justify-center rounded-full",
        size === "default" ? "size-4" : "size-3.5",
        className
      )}
    >
      {visual.breathing ? (
        <span
          className={cn(
            "absolute animate-ping rounded-full opacity-75",
            pingSize,
            visual.dotClassName
          )}
        />
      ) : null}
      <span
        className={cn("relative rounded-full", dotSize, visual.dotClassName)}
      />
    </span>
  );
}

export function EntryNodeStatusPill({
  className,
  status,
}: {
  className?: string;
  status?: EntryNodeStatus;
}) {
  const statusLabel = status?.label?.trim() || "Unknown";
  const visual = getStatusVisual(resolveTone(status));

  return (
    <span
      className={cn(
        "flex h-5 shrink-0 items-center gap-2.5 rounded-full py-0.5 pr-1 pl-2.5 font-normal text-xs leading-none",
        visual.pillClassName,
        className
      )}
    >
      <span className="truncate">{statusLabel}</span>
      <EntryNodeStatusDot size="small" status={status} />
    </span>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import { type CSSProperties, type ReactNode, useEffect, useState } from "react";
import { useEntryNode } from "./entry-node.context";
import type { EntryNodeDragAngle } from "./entry-node.types";

interface EntryNodeDragFrameStyle extends CSSProperties {
  "--entry-node-drag-gradient-angle"?: string;
}

function getGradientAngle(dragAngle: EntryNodeDragAngle) {
  return dragAngle - 90;
}

function getNearestPeriodicGradientAngle(
  gradientAngle: number,
  previousGradientAngle: number | undefined
) {
  if (previousGradientAngle === undefined) {
    return gradientAngle;
  }

  let nextGradientAngle = gradientAngle;

  while (nextGradientAngle - previousGradientAngle > 90) {
    nextGradientAngle -= 180;
  }

  while (nextGradientAngle - previousGradientAngle < -90) {
    nextGradientAngle += 180;
  }

  return nextGradientAngle;
}

function useDragGradientAngle(dragAngle: EntryNodeDragAngle | undefined) {
  const [gradientAngle, setGradientAngle] = useState<number | undefined>(() => {
    if (dragAngle === undefined || !Number.isFinite(dragAngle)) {
      return undefined;
    }

    return getGradientAngle(dragAngle);
  });

  useEffect(() => {
    if (dragAngle === undefined || !Number.isFinite(dragAngle)) {
      setGradientAngle(undefined);
      return;
    }

    setGradientAngle((previousGradientAngle) =>
      getNearestPeriodicGradientAngle(
        getGradientAngle(dragAngle),
        previousGradientAngle
      )
    );
  }, [dragAngle]);

  return gradientAngle;
}

function getDragFrameStyle(
  gradientAngle: number | undefined
): EntryNodeDragFrameStyle | undefined {
  if (gradientAngle === undefined) {
    return undefined;
  }

  return { "--entry-node-drag-gradient-angle": `${gradientAngle}deg` };
}

export function EntryNodeDragFrame({
  children,
  className,
  dragAngle,
  dragging = false,
}: {
  children?: ReactNode;
  className?: string;
  dragAngle?: EntryNodeDragAngle;
  dragging?: boolean;
}) {
  const gradientAngle = useDragGradientAngle(dragAngle);

  if (!(dragging || dragAngle !== undefined)) {
    return <>{children}</>;
  }

  return (
    <div
      className={cn("entry-node-drag-frame inline-flex rounded-lg", className)}
      data-dragging={dragging ? "true" : undefined}
      data-slot="entry-node-drag-frame"
      style={getDragFrameStyle(gradientAngle)}
    >
      {children}
    </div>
  );
}

export function EntryNodeDragStateFrame({
  children,
  className,
}: {
  children?: ReactNode;
  className?: string;
}) {
  const {
    state: { interaction },
  } = useEntryNode();

  return (
    <EntryNodeDragFrame
      className={className}
      dragAngle={interaction?.dragAngle}
      dragging={interaction?.dragging}
    >
      {children}
    </EntryNodeDragFrame>
  );
}

"use client";

import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";
import { Plus } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import type { EntryNodeConnectionSide } from "./entry-node.types";

export function EntryNodeConnectionButton({
  className,
  side,
}: {
  className?: string;
  side: EntryNodeConnectionSide;
}) {
  const { actions } = useEntryNode();

  return (
    <Button
      aria-label={`Connect from ${side}`}
      className={cn(
        "entry-node-connection-button absolute flex size-5 items-center justify-center rounded-full border border-blue-500 bg-transparent p-0 text-blue-500 shadow-none transition-[background,border-color,box-shadow] hover:text-blue-500 focus-visible:ring-2 focus-visible:ring-blue-500/60",
        className
      )}
      data-side={side}
      data-slot="entry-node-connection-button"
      onKeyDown={(event) => {
        if (event.key === "Enter" || event.key === " ") {
          actions.startConnection?.(side, event);
        }
      }}
      onPointerDown={(event) => {
        actions.startConnection?.(side, event);
      }}
      size={null}
      type="button"
      variant={null}
    >
      <Plus aria-hidden className="size-2.5" />
    </Button>
  );
}

"use client";

import { EntryNodeConnectionButton } from "./entry-node.connection-button";
import type { EntryNodeConnectionSide } from "./entry-node.types";

const CONNECTION_SIDES = [
  "top",
  "right",
  "bottom",
  "left",
] as const satisfies readonly EntryNodeConnectionSide[];

