"use client";

import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";
import { Brain, Router } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import { EntryNodeStatusDot, EntryNodeStatusPill } from "./entry-node.status";
import type { EntryNodeDomain } from "./entry-node.types";

function getAccessDomain(
  fallbackName: string,
  domain: EntryNodeDomain | undefined
) {
  return (
    domain ?? {
      label: "Access domain",
      value: fallbackName,
    }
  );
}

export function EntryNodeHeader({ className }: { className?: string }) {
  const {
    actions,
    meta,
    state: { domains, states },
  } = useEntryNode();
  const expanded = meta.expanded ?? false;
  const accessDomain = getAccessDomain(states.name, domains?.access);
  const status = accessDomain.status ?? states.status;
  const statusLabel = status?.label?.trim() || "Unknown";
  const Icon = expanded ? Router : Brain;

  return (
    <Button
      aria-expanded={expanded}
      aria-label={`${expanded ? "Collapse" : "Expand"} ${accessDomain.value}`}
      className={cn(
        "entry-node-card-header group flex h-auto w-full min-w-0 items-center justify-start rounded-none border-0 bg-transparent text-left font-normal text-zinc-50 shadow-none transition-[min-height,padding] hover:bg-transparent hover:text-zinc-50",
        className
      )}
      data-slot="entry-node-header"
      onClick={() => {
        if (expanded) {
          actions.collapse?.();
          return;
        }

        actions.expand?.();
      }}
      size={null}
      title={accessDomain.value}
      type="button"
      variant={null}
    >
      <div className="entry-node-card-header-content min-w-0 flex-1">
        <div className="flex min-w-0 items-center justify-between gap-2">
          <span className="flex min-w-0 items-center gap-2">
            <Icon aria-hidden className="size-4 shrink-0 text-zinc-50" />
            <span
              className={cn(
                "entry-node-card-title min-w-0 truncate font-normal",
                expanded
                  ? "text-muted-foreground text-xs leading-4"
                  : "text-sm text-zinc-50 leading-5"
              )}
            >
              {expanded ? accessDomain.label : accessDomain.value}
            </span>
          </span>
          <span className="entry-node-card-status min-w-0 shrink-0">
            <EntryNodeStatusPill
              className="entry-node-card-status-pill max-w-28"
              status={{ label: statusLabel, tone: status?.tone }}
            />
            <EntryNodeStatusDot
              className="entry-node-card-status-dot"
              size="collapsed"
              status={{ label: statusLabel, tone: status?.tone }}
            />
          </span>
        </div>
        <span className="entry-node-card-access-value mt-1 min-w-0 truncate font-normal text-sm text-zinc-50 leading-5">
          {accessDomain.value}
        </span>
      </div>
    </Button>
  );
}

"use client";

import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";
import { Check, Copy } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import { EntryNodeStatusDot } from "./entry-node.status";
import type { EntryNodeDomain, EntryNodeDomainKey } from "./entry-node.types";

export function EntryNodeDomainSection({
  className,
  domain,
  domainKey,
}: {
  className?: string;
  domain: EntryNodeDomain;
  domainKey: EntryNodeDomainKey;
}) {
  const {
    actions,
    state: { copiedDomainKey },
  } = useEntryNode();
  const copied = copiedDomainKey === domainKey;

  return (
    <section
      className={cn(
        "entry-node-domain-section flex min-w-0 flex-col gap-2 rounded-lg pb-1.5",
        className
      )}
      data-slot="entry-node-domain-section"
    >
      <div className="flex min-w-0 items-center justify-between gap-2">
        <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
          {domain.label}
        </span>
        <EntryNodeStatusDot size="small" status={domain.status} />
      </div>
      <Button
        className={cn(
          "entry-node-domain-copy group flex h-7 w-full min-w-0 items-center justify-between gap-2 rounded-md border-0 bg-transparent px-2.5 py-1.5 text-left font-normal text-xs text-zinc-50 leading-4 shadow-none transition-[background,box-shadow] hover:text-zinc-50",
          copied && "entry-node-domain-copy-copied"
        )}
        data-copied={copied ? "true" : undefined}
        data-slot="entry-node-domain-copy"
        onClick={() => {
          Promise.resolve(actions.copyDomain(domainKey, domain.value)).catch(
            () => undefined
          );
        }}
        size={null}
        title={domain.value}
        type="button"
        variant={null}
      >
        <span className="min-w-0 truncate">{domain.value}</span>
        {copied ? (
          <Check aria-hidden className="size-4 shrink-0" />
        ) : (
          <Copy
            aria-hidden
            className="size-4 shrink-0 opacity-0 transition-opacity group-hover:opacity-100 group-focus-visible:opacity-100"
          />
        )}
      </Button>
    </section>
  );
}

"use client";

import { cn } from "@workspace/ui/lib/utils";

import { useEntryNode } from "./entry-node.context";
import { EntryNodeDomainSection } from "./entry-node.domain-section";
import type { EntryNodeDomain, EntryNodeDomainKey } from "./entry-node.types";

const BODY_DOMAIN_KEYS = [
  "public",
  "private",
] as const satisfies readonly EntryNodeDomainKey[];

function getBodyDomains(domains: {
  private?: EntryNodeDomain;
  public?: EntryNodeDomain;
}) {
  return BODY_DOMAIN_KEYS.flatMap((domainKey) => {
    const domain = domains[domainKey];
    return domain ? [{ domain, domainKey }] : [];
  });
}

export function EntryNodeDomainList({ className }: { className?: string }) {
  const {
    state: { domains },
  } = useEntryNode();
  const bodyDomains = getBodyDomains({
    private: domains?.private,
    public: domains?.public,
  });

  return (
    <div
      className={cn("flex min-w-0 flex-col gap-2.5 pt-2.5", className)}
      data-slot="entry-node-domain-list"
    >
      {bodyDomains.map(({ domain, domainKey }) => (
        <EntryNodeDomainSection
          domain={domain}
          domainKey={domainKey}
          key={domainKey}
        />
      ))}
    </div>
  );
}

