  --entry-node-card-width-collapsed: calc(var(--spacing) * 40);
  --entry-node-card-height-collapsed: calc(var(--spacing) * 10);
  --entry-node-card-width-expanded: calc(var(--spacing) * 66.75);
  --entry-node-card-height-expanded: calc(var(--spacing) * 55);
  --entry-node-connection-size: calc(var(--spacing) * 5);
  --entry-node-connection-gap: calc(var(--spacing) * 1.5);
  --entry-node-bounds-gutter: calc(
    var(--entry-node-connection-size) +
    var(--entry-node-connection-gap)
  );
  width: calc(
    var(--entry-node-card-width-collapsed) +
    var(--entry-node-bounds-gutter) *
    2
  );
  height: calc(
    var(--entry-node-card-height-collapsed) +
    var(--entry-node-bounds-gutter) *
    2
  );
  transition:
    width 180ms cubic-bezier(0.16, 1, 0.3, 1),
    height 180ms cubic-bezier(0.16, 1, 0.3, 1);
}

.entry-node-bounds[data-state="expanded"] {
  width: calc(
    var(--entry-node-card-width-expanded) +
    var(--entry-node-bounds-gutter) *
    2
  );
  height: calc(
    var(--entry-node-card-height-expanded) +
    var(--entry-node-bounds-gutter) *
    2
  );
}

.entry-node-card {
