  width: var(--entry-node-card-width-collapsed);
  min-height: var(--entry-node-card-height-collapsed);
  background: rgb(255 255 255 / 5%);
  transition:
    width 180ms cubic-bezier(0.16, 1, 0.3, 1),
    min-height 180ms cubic-bezier(0.16, 1, 0.3, 1),
    background 150ms ease,
    box-shadow 150ms ease;
}

.entry-node-bounds[data-state="expanded"] .entry-node-card {
  width: var(--entry-node-card-width-expanded);
  min-height: var(--entry-node-card-height-expanded);
}

.entry-node-card-header {
  min-height: var(--entry-node-card-height-collapsed);
  padding: calc(var(--spacing) * 2.5);
}

.entry-node-card-header,
.entry-node-card-header:hover,
