.entry-node-drag-frame {
  /* Figma node 12:549: four 1px inside linear-gradient strokes, painted as an outer effect. */
  --entry-node-drag-gradient-angle: 99.5deg;
  --entry-node-drag-stroke: rgb(255 255 255 / 15%);
  --entry-node-drag-stroke-clear: rgb(255 255 255 / 0%);
  --entry-node-drag-stroke-stop: 16.72%;
  position: relative;
  transition: --entry-node-drag-gradient-angle 180ms
    cubic-bezier(0.16, 1, 0.3, 1);
}

.entry-node-drag-frame::before {
  position: absolute;
  inset: -4px;
  padding: 1px;
  pointer-events: none;
  content: "";
  background:
    linear-gradient(
      var(--entry-node-drag-gradient-angle),
      var(--entry-node-drag-stroke) 0%,
      var(--entry-node-drag-stroke-clear) var(--entry-node-drag-stroke-stop)
    ),
    linear-gradient(
      var(--entry-node-drag-gradient-angle),
      var(--entry-node-drag-stroke) 0%,
      var(--entry-node-drag-stroke-clear) var(--entry-node-drag-stroke-stop)
    ),
    linear-gradient(
      calc(var(--entry-node-drag-gradient-angle) + 180deg),
      var(--entry-node-drag-stroke) 0%,
      var(--entry-node-drag-stroke-clear) var(--entry-node-drag-stroke-stop)
    ),
    linear-gradient(
      calc(var(--entry-node-drag-gradient-angle) + 180deg),
      var(--entry-node-drag-stroke) 0%,
      var(--entry-node-drag-stroke-clear) var(--entry-node-drag-stroke-stop)
    );
  border-radius: inherit;
  -webkit-mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  mask:
    linear-gradient(#000 0 0) content-box,
    linear-gradient(#000 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  transition: --entry-node-drag-gradient-angle 180ms
    cubic-bezier(0.16, 1, 0.3, 1);
}

